  /* ✅ Centre mieux sur mobile + PC */
.page{
  max-width: 1180px;
  margin: 0 auto;
  padding: 18px 18px 44px;
}
.grid{
  display:grid;
  grid-template-columns: 1.25fr .75fr;
  gap:14px;
  align-items:start;
}
@media (max-width: 980px){
  .grid{grid-template-columns:1fr;}
}

/* ✅ Logo carré + icône seule (crop si le svg contient du texte) */
.logoBox{
  width:64px;height:64px;
  border-radius:18px;
  background:rgba(47,91,255,.10);
  border:1px solid rgba(47,91,255,.18);
  display:flex;align-items:center;justify-content:center;
  overflow:hidden; /* important pour crop */
}
.brandLogo{
  width:140%;
  height:140%;
  object-fit:cover;              /* crop */
  object-position:left center;   /* garde l’icône à gauche */
  display:block;
}

/* ✅ Plan cards: centre proprement */
.plans{
  padding:14px;
  display:grid;
  grid-template-columns: repeat(3, 1fr);
  gap:12px;
}
@media (max-width: 980px){
  .plans{grid-template-columns:1fr;}
}
.planCard{
  border:1px solid var(--border);
  border-radius:18px;
  padding:16px;
  background:linear-gradient(180deg, rgba(47,91,255,.10), transparent 65%);
  min-height:190px;
}
.planCard.active{
  outline:2px solid rgba(47,91,255,.45);
  box-shadow:0 0 0 6px rgba(47,91,255,.12);
}

/* ✅ Quantité jolie sur PC */
.qty{
  display:flex;
  align-items:center;
  gap:10px;
  padding:8px;
  border-radius:14px;
  border:1px solid var(--fieldBorder);
  background:var(--field);
  box-shadow:0 10px 35px rgba(0,0,0,.08);
}
.qtyBtn{
  width:36px;height:36px;
  border-radius:12px;
  border:1px solid var(--border);
  background:rgba(255,255,255,.06);
  color:var(--text);
  font-weight:900;
  cursor:pointer;
}
@media (prefers-color-scheme: light){
  .qtyBtn{background:#fff;}
}
.qtyInput{
  width:64px;
  text-align:center;
  border:0;
  background:transparent;
  color:var(--text);
  font-weight:900;
  font-size:14px;
  outline:none;
}

/* ✅ Toggle switch pour flags */
.toggle{
  position:relative;
  width:52px;height:32px;
  display:inline-flex;
  align-items:center;
  justify-content:center;
}
.toggle input{
  position:absolute;
  inset:0;
  opacity:0;
  cursor:pointer;
}
.toggle .track{
  width:52px;height:32px;
  border-radius:999px;
  border:1px solid var(--border);
  background:rgba(255,255,255,.06);
  position:relative;
  transition: .15s ease;
}
.toggle .track:after{
  content:"";
  width:26px;height:26px;
  border-radius:999px;
  position:absolute;
  left:3px;top:50%;
  transform:translateY(-50%);
  background:rgba(255,255,255,.9);
  transition:.15s ease;
}
.toggle input:checked + .track{
  background:linear-gradient(180deg,var(--primary),var(--primary2));
  border-color:rgba(47,91,255,.45);
}
.toggle input:checked + .track:after{
  left:23px;
}
.toggle input:disabled + .track{
  opacity:.65;
  cursor:not-allowed;
}
